    unordered_map<long long, vector<pair<long long, long long>>> graph;
    for (auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long w = edge[2];
        graph[u].push_back({v, w});
        graph[v].push_back({u, w});
    }

    // Sort edges by weight
    vector<pair<long long, long long>> sorted_edges;
    for (auto& edge : edges) {
        sorted_edges.push_back({edge[2], edge[0], edge[1]});
    }
    sort(sorted_edges.begin(), sorted_edges.end());

    // Use a priority queue to keep track of the maximum edge weight in each component
    priority_queue<long long> max_edges;

    // Use a union-find data structure to track connected components
    vector<long long> parent(n);
    vector<long long> rank(n);

    function<long long(long long)> find = [&](long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    function<void(long long, long long)> union_sets = [&](long long x, long long y) {
        long long root_x = find(x);
        long long root_y = find(y);
        if (root_x != root_y) {
            if (rank[root_x] > rank[root_y]) {
                parent[root_y] = root_x;
            } else {
                parent[root_x] = root_y;
                if (rank[root_x] == rank[root_y]) {
                    rank[root_y]++;
                }
            }
        }
    };

    // Initialize parent and rank arrays
    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
        rank[i] = 0;
    }

    // Process edges in order of increasing weight
    for (auto& edge : sorted_edges) {
        long long w = edge.first;
        long long u = edge.second;
        long long v = edge.third;

        long long root_u = find(u);
        long long root_v = find(v);

        if (root_u != root_v) {
            union_sets(root_u, root_v);
            max_edges.push(w);
        }
    }

